import React, { useState } from 'react';
import { BrowserRouter as Router, Route, Routes, Link } from 'react-router-dom';
import './Welcome_game.css';
import './Game.js'

function Welcome_game() {
    return (
            <div>
            <div className="home">
                <h1 className="title"> PONG </h1>
                <div style={{ width: '100%', height: '0', paddingBottom: '57%', position: 'relative' }}>
                <iframe 
                    src="https://giphy.com/embed/z4Rl0fxSYfvKUzfJU1" 
                    width="100%" 
                    height="100%" 
                    style={{ position: 'absolute' }} 
                    frameBorder="0" 
                    className="giphy-embed" 
                    allowFullScreen
                ></iframe>
            </div>
            <p><a href="https://giphy.com/gifs/games-pong-atari-z4Rl0fxSYfvKUzfJU1">via GIPHY</a></p>
                <button className="buttonGame">
                    <Link to="/Game" class="text-decoration-none text-dark">Play</Link>
                </button>
            </div>
        </div>

    );
}

export default Welcome_game;
